// ============================================
// CODE NODE - Parsing AI Agent + Formatage HTML
// ============================================

const item = $input.first();

// Extraire la réponse du AI Agent natif n8n (sortie = item.json.output)
let rawContent;
try {
  rawContent = item.json.output;
  if (!rawContent) throw new Error('Champ output vide');
} catch (e) {
  throw new Error('Réponse AI Agent invalide : ' + JSON.stringify(item.json));
}

// Parser le JSON Mistral
let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (e) {
  // Tentative d'extraction JSON si entouré de texte ou balises markdown
  const jsonMatch = rawContent.match(/```json([\s\S]*?)```/) || rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[1] || jsonMatch[0]);
    } catch (e2) {
      throw new Error('Impossible de parser le JSON : ' + rawContent.substring(0, 200));
    }
  } else {
    throw new Error('Aucun JSON trouvé dans la réponse : ' + rawContent.substring(0, 200));
  }
}

const metiers = parsed.metiers || [];

if (metiers.length === 0) {
  throw new Error('Aucun métier retourné par Mistral. Réponse brute : ' + rawContent.substring(0, 300));
}

// Badge couleur selon compatibilité
function getBadgeColor(score) {
  if (score >= 85) return '#10b981'; // vert
  if (score >= 70) return '#f59e0b'; // orange
  return '#6366f1'; // violet
}

// HTML responsive
const htmlTable = `
<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Résultats Orientation Professionnelle</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: 'Segoe UI', system-ui, sans-serif; background: #f8fafc; color: #1e293b; padding: 20px; }
    h1 { text-align: center; font-size: 1.8rem; color: #1e40af; margin-bottom: 8px; }
    .subtitle { text-align: center; color: #64748b; margin-bottom: 32px; font-size: 0.95rem; }
    .cards { display: flex; flex-direction: column; gap: 20px; max-width: 800px; margin: 0 auto; }
    .card { background: white; border-radius: 16px; padding: 24px; box-shadow: 0 2px 12px rgba(0,0,0,0.08); border-left: 5px solid #6366f1; transition: transform 0.2s; }
    .card:hover { transform: translateY(-2px); box-shadow: 0 6px 20px rgba(0,0,0,0.12); }
    .card-header { display: flex; justify-content: space-between; align-items: flex-start; flex-wrap: wrap; gap: 12px; margin-bottom: 12px; }
    .job-name { font-size: 1.25rem; font-weight: 700; color: #1e293b; }
    .badge { padding: 6px 14px; border-radius: 999px; color: white; font-weight: 700; font-size: 0.9rem; white-space: nowrap; }
    .description { color: #475569; line-height: 1.6; margin-bottom: 14px; }
    .salary { display: inline-block; background: #f0fdf4; color: #166534; padding: 4px 12px; border-radius: 8px; font-weight: 600; font-size: 0.9rem; margin-bottom: 14px; }
    .raisons-title { font-weight: 600; color: #475569; font-size: 0.85rem; text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 8px; }
    .raisons { list-style: none; }
    .raisons li { padding: 4px 0; padding-left: 20px; position: relative; color: #334155; font-size: 0.92rem; }
    .raisons li::before { content: '✓'; position: absolute; left: 0; color: #10b981; font-weight: 700; }
    .footer { text-align: center; margin-top: 32px; color: #94a3b8; font-size: 0.8rem; }
    @media (max-width: 600px) { .card { padding: 16px; } .job-name { font-size: 1.1rem; } }
  </style>
</head>
<body>
  <h1>🎯 Tes Métiers Idéaux</h1>
  <p class="subtitle">Analyse personnalisée basée sur ton profil — ${new Date().toLocaleDateString('fr-FR')}</p>
  <div class="cards">
    ${metiers.map((m, i) => `
    <div class="card" style="border-left-color: ${getBadgeColor(m.compatibilite)}">
      <div class="card-header">
        <div class="job-name">${i + 1}. ${m.nom}</div>
        <div class="badge" style="background: ${getBadgeColor(m.compatibilite)}">${m.compatibilite}% match</div>
      </div>
      <p class="description">${m.description}</p>
      <div class="salary">💰 ${m.salaire_moyen} / an brut</div>
      <div class="raisons-title">Pourquoi ça te correspond</div>
      <ul class="raisons">
        ${m.raisons.map(r => `<li>${r}</li>`).join('')}
      </ul>
    </div>`).join('')}
  </div>
  <div class="footer">Généré par Agent Orientation Pro · Mistral AI</div>
</body>
</html>
`;

return {
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    metiers: metiers,
    total_metiers: metiers.length,
    html: htmlTable,
    usage: {
      prompt_tokens: 0,
      completion_tokens: 0,
      total_tokens: 0
    }
  }
};
